import android.content.Context
import android.content.SharedPreferences
import android.hardware.biometrics.BiometricPrompt
import android.os.Build
import android.os.CancellationSignal
import androidx.annotation.RequiresApi
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt.PromptInfo
import java.util.concurrent.Executor
import java.util.concurrent.Executors

class BiometricAuthManager(private val context: Context) {
    private val sharedPreferences: SharedPreferences =
        context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)
    private val executor: Executor = Executors.newSingleThreadExecutor()
    private var cancellationSignal: CancellationSignal? = null
    private var biometricPrompt: BiometricPrompt? = null

    fun isBiometricAuthAvailable(): Boolean {
        val biometricManager = BiometricManager.from(context)
        return biometricManager.canAuthenticate() == BiometricManager.BIOMETRIC_SUCCESS
    }

    fun isUserAuthenticated(): Boolean {
        return sharedPreferences.getBoolean("is_authenticated", false)
    }

    fun setAuthenticated() {
        sharedPreferences.edit().putBoolean("is_authenticated", true).apply()
    }

    fun clearAuthentication() {
        sharedPreferences.edit().putBoolean("is_authenticated", false).apply()
    }

    @RequiresApi(api = Build.VERSION_CODES.P)
    fun authenticate(activity: AppCompatActivity, onAuthSuccess: () -> Unit, onAuthFailure: () -> Unit) {
        if (!isBiometricAuthAvailable()) {
            onAuthFailure()
            return
        }

        val promptInfo = PromptInfo.Builder()
            .setTitle("Biometric Authentication")
            .setSubtitle("Use your fingerprint to access the app")
            .setNegativeButtonText("Use password")
            .setConfirmationRequired(true)
            .build()

        biometricPrompt = BiometricPrompt(activity, executor, object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                super.onAuthenticationSucceeded(result)
                setAuthenticated()
                onAuthSuccess()
            }

            override fun onAuthenticationFailed() {
                super.onAuthenticationFailed()
                onAuthFailure()
            }

            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                super.onAuthenticationError(errorCode, errString)
                if (errorCode != BiometricPrompt.ERROR_USER_CANCELED) {
                    onAuthFailure()
                }
            }
        })

        cancellationSignal = CancellationSignal()
